SELECT COUNT(reply_id) AS total_edited_replies, COUNT(DISTINCT user_id) AS unique_editors
FROM replies
WHERE is_edited = 1;

SELECT COUNT(*) 
FROM topics 
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Ideas & Suggestions');

SELECT *
FROM topics
WHERE view_count = (SELECT MAX(view_count) FROM topics);

SELECT like_count 
FROM replies 
WHERE reply_id = 0;

SELECT user_id
FROM replies
WHERE like_count = (SELECT MAX(like_count) FROM replies);
